import{d as s,o as r,c as o,e as i,j as a,t as n,_ as d,a as h,E as c,ag as u}from"./chunks/framework.Cqf6AMW8.js";const m=["href"],p=["src","alt"],f={class:"yt-card__content"},v={class:"yt-card__title"},g={key:0,class:"yt-card__description"},b=s({__name:"YouTubeCard",props:{title:{},href:{},thumbnail:{},description:{}},setup(t){return(l,e)=>(r(),o("a",{class:"yt-card",href:t.href,target:"_blank",rel:"noreferrer"},[t.thumbnail?(r(),o("img",{key:0,class:"yt-card__thumb",src:t.thumbnail,alt:t.title},null,8,p)):i("",!0),a("div",f,[e[0]||(e[0]=a("div",{class:"yt-card__label"},"Video",-1)),a("div",v,n(t.title),1),t.description?(r(),o("div",g,n(t.description),1)):i("",!0),e[1]||(e[1]=a("div",{class:"yt-card__cta"},"Watch on YouTube →",-1))])],8,m))}}),w=d(b,[["__scopeId","data-v-cf88381c"]]),k=JSON.parse('{"title":"How to create a Minecraft Server (2026)","titleTemplate":"Vite & Vue powered static site generator","description":"","frontmatter":{"title":"How to create a Minecraft Server (2026)","titleTemplate":"Vite & Vue powered static site generator","layout":"doc","outline":{"level":[2,3],"label":"Contents"}},"headers":[],"relativePath":"videos/minecraft-server-2026.md","filePath":"en/videos/minecraft-server-2026.md","lastUpdated":1776266781000}'),y={name:"videos/minecraft-server-2026.md"},T=s({...y,setup(t){return(l,e)=>(r(),o("div",null,[e[0]||(e[0]=a("h1",{id:"minecraft-server-tutorial-2026",tabindex:"-1"},[h("Minecraft Server Tutorial (2026) "),a("a",{class:"header-anchor",href:"#minecraft-server-tutorial-2026","aria-label":'Permalink to "Minecraft Server Tutorial (2026)"'},"​")],-1)),c(w,{title:"How to create a Minecraft Server (2026)",href:"https://www.youtube.com/watch?v=-h_D9IEJOeM",thumbnail:"https://img.youtube.com/vi/-h_D9IEJOeM/maxresdefault.jpg",description:"A walkthrough of the feature shown in this guide."}),e[1]||(e[1]=u('<h2 id="general-information" tabindex="-1">General Information <a class="header-anchor" href="#general-information" aria-label="Permalink to &quot;General Information&quot;">​</a></h2><h3 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to &quot;Terminology&quot;">​</a></h3><p>Before we continue with this tutorial lets talk about some basic terminology I will use going forward so you dont get confused 😃</p><table tabindex="0"><thead><tr><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td>Client</td><td>The Client is effectively the game that you start on your local computer. Lets compare it to a plane for now.</td></tr><tr><td>Server</td><td>An instance of minecraft running in your terminal without a graphical preview, this is what your client connects to. You can imagine this similar to a big airport.</td></tr><tr><td>Terminal</td><td>The Terminal, Command Prompt or &quot;CMD&quot; is a Windows Application that lets you run &quot;commands&quot;. It lets you interact with apps that dont have a graphical user interface (GUI)</td></tr><tr><td>Vanilla</td><td>This word in general describes the unmodified version of a game, directly as it came from the game developer. This definition is not unique to Minecraft.</td></tr><tr><td>Server Software</td><td>Once we want plugins and mods to work on our server, the vanilla <strong>server</strong> software will not be sufficient anymore. Therefore developers created their own &quot;Server Software&quot;, which includes all the features from the vanilla server aswell new ones like plugin support.</td></tr><tr><td>Mod Loaders</td><td>Similar to Server Software, Mod Loaders describe modified Version of the vanilla <strong>client</strong> that include further features like mod support and performance improvements.</td></tr></tbody></table><h3 id="java" tabindex="-1">Choosing the correct Java Version <a class="header-anchor" href="#java" aria-label="Permalink to &quot;Choosing the correct Java Version {#java}&quot;">​</a></h3><p>Minecraft is a pretty old game at this point and to keep the code safe and up to modern standards Mojang updated they Java version of the game every few updates. When want to run a minecraft server we need to have the java version installed on our computer that our server was originally developed with.</p><table tabindex="0"><thead><tr><th>Minecraft Version</th><th style="text-align:right;">Java</th><th>Download</th></tr></thead><tbody><tr><td>1.16.5 and older</td><td style="text-align:right;">Java 8</td><td><a href="https://adoptium.net/de/temurin/releases?version=8" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>1.17</td><td style="text-align:right;">Java 16</td><td><a href="https://adoptium.net/de/temurin/releases?version=16" target="_blank" rel="noreferrer">Adoptium</a>*</td></tr><tr><td>1.18 - 1.20.4</td><td style="text-align:right;">Java 17</td><td><a href="https://adoptium.net/de/temurin/releases?version=17" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>1.20.5</td><td style="text-align:right;">Java 21</td><td><a href="https://adoptium.net/de/temurin/releases?version=21" target="_blank" rel="noreferrer">Adoptium</a></td></tr><tr><td>26.1 and newer</td><td style="text-align:right;">Java 25</td><td><a href="https://adoptium.net/de/temurin/releases?version=25" target="_blank" rel="noreferrer">Adoptium</a></td></tr></tbody></table><p>*only JDK available</p><p>When you have decided on which Minecraft Version your server will run, click the download link next to the corresponding Java version. This will redirect you to download page for Eclipse Temurin.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Temurin is a free, open-source distribution of the Java Development Kit (JDK) built from OpenJDK and maintained by the Eclipse Adoptium project.</p></div><h3 id="batch" tabindex="-1">Creating a batch (.bat) file to start the Server <a class="header-anchor" href="#batch" aria-label="Permalink to &quot;Creating a batch (.bat) file to start the Server {#batch}&quot;">​</a></h3><p>In order for the minecraft server to run we need to create a batch file.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>You can think of the batch file as a &quot;shortcut&quot; or &quot;preset&quot; that tells the server file how to run the server e.g. how much RAM it should be able to use etc.</p></div><ol><li>Step: Creating the file <ul><li>Make sure to have &quot;show file extension&quot; checked in the Explorer under: <ul><li>View &gt; Show &gt; File Extension</li></ul></li></ul></li></ol><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">java</span></span></code></pre></div><h2 id="vanilla" tabindex="-1">Vanilla Server <a class="header-anchor" href="#vanilla" aria-label="Permalink to &quot;Vanilla Server {#vanilla}&quot;">​</a></h2><p>This section is meant to explain how to create a basic minecraft vanilla server. This means we will run an unmodified game server which does not support plugins or mods. If you want to create an SMP server for your friends I would recommend taking a look at the <a href="#spigot">Spigot Section</a> instead.</p>',17))]))}});export{k as __pageData,T as default};
